## Word Search in Grid

Given a 2D grid of characters and a word, determine if the word exists in the grid following adjacent (up/down/left/right) cells without reusing the same cell. This is DFS + backtracking: explore each cell as a potential start, mark cells visited, recurse into neighbors, and unmark on backtrack.

```python
# Python — word search (LeetCode 79)
def exist(board, word):
    rows, cols = len(board), len(board[0])

    def dfs(r, c, idx):
        if idx == len(word):      # matched all characters
            return True
        if r < 0 or r >= rows or c < 0 or c >= cols:
            return False
        if board[r][c] != word[idx]:
            return False

        temp = board[r][c]
        board[r][c] = '#'         # mark as visited in-place
        found = (
            dfs(r + 1, c, idx + 1) or
            dfs(r - 1, c, idx + 1) or
            dfs(r, c + 1, idx + 1) or
            dfs(r, c - 1, idx + 1)
        )
        board[r][c] = temp        # restore (backtrack)
        return found

    for r in range(rows):
        for c in range(cols):
            if dfs(r, c, 0):
                return True
    return False

# Word Search II — find all words from a list (uses Trie)
class TrieNode:
    def __init__(self):
        self.children = {}
        self.word = None

def find_words(board, words):
    root = TrieNode()
    for w in words:
        node = root
        for ch in w:
            node = node.children.setdefault(ch, TrieNode())
        node.word = w

    rows, cols = len(board), len(board[0])
    result = set()

    def dfs(r, c, node):
        if r < 0 or r >= rows or c < 0 or c >= cols or board[r][c] == '#':
            return
        ch = board[r][c]
        if ch not in node.children:
            return
        next_node = node.children[ch]
        if next_node.word:
            result.add(next_node.word)
        board[r][c] = '#'
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            dfs(r + dr, c + dc, next_node)
        board[r][c] = ch

    for r in range(rows):
        for c in range(cols):
            dfs(r, c, root)
    return list(result)
```

```java
// Java — word search
public class WordSearch {
    private int[][] dirs = {{1,0},{-1,0},{0,1},{0,-1}};

    public boolean exist(char[][] board, String word) {
        int rows = board.length, cols = board[0].length;
        for (int r = 0; r < rows; r++)
            for (int c = 0; c < cols; c++)
                if (dfs(board, word, r, c, 0)) return true;
        return false;
    }

    private boolean dfs(char[][] board, String word, int r, int c, int idx) {
        if (idx == word.length()) return true;
        if (r < 0 || r >= board.length || c < 0 || c >= board[0].length)
            return false;
        if (board[r][c] != word.charAt(idx)) return false;

        char temp = board[r][c];
        board[r][c] = '#';
        for (int[] d : dirs)
            if (dfs(board, word, r + d[0], c + d[1], idx + 1)) {
                board[r][c] = temp;
                return true;
            }
        board[r][c] = temp;
        return false;
    }
}
```

**Complexity:** O(M * N * 4^L) where M×N is the grid size and L is the word length. In practice much faster due to early termination.

**Interview Tip:** The in-place marking trick (`board[r][c] = '#'`) avoids allocating a visited array and is the expected optimization. Always restore the cell after the recursive call — forgetting this is the most common bug. For Word Search II, mention the Trie structure to impress interviewers.

